import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as t,c,a as o,b as d,e as r,f as a}from"./app-e3619739.js";const n={},s=a('<h3 id="css简介" tabindex="-1"><a class="header-anchor" href="#css简介" aria-hidden="true">#</a> CSS简介</h3><p>层叠样式表 ( Cascading Style Sheets ) 。CSS 也是一种标记语言，用于给 HTML 结构设置样式，例如：文字大小、颜色、元素宽高等等。</p><h3 id="css选择器" tabindex="-1"><a class="header-anchor" href="#css选择器" aria-hidden="true">#</a> CSS选择器</h3><ol><li>CSS基本选择器</li></ol><blockquote><ol><li>通配选择器：选中所有标签，一般用于清除样式。 <code>* {color:red} </code></li><li>元素选择器：选中所有同种标签，但是不能差异化选择。<code>h1 {color:red} </code></li><li>类选择器： 选中所有特定类名（ class 值）的元素 。<code>.say {color:red} </code></li><li>ID选择器： 选中特定 id 值的那个元素（唯一的） <code>#earthy {color:red} </code></li></ol></blockquote><ol start="2"><li>CSS复杂选择器</li></ol><blockquote><ol><li>交集选择器：选中同时符合多个条件的元素。语法：选择器1选择器2...选择器n {} <code> p.beauty { color: blue;}</code></li><li>并集选择器：语法：选择器1, 选择器2, ... 选择器n {} <code>.rich, .beauty { font-size: 40px;}</code></li><li>后代选择器：语法：选择器1 选择器2 ... 选择器n {} <code>ul li a { color: orange; } </code></li><li>子元素选择器：选中指定元素中，符合要求的子元素（儿子元素） 语法： 选择器1 &gt; 选择器2 &gt; 选择器3 &gt; 选择器n {} <code>.persons&gt;a{ color: red; }</code></li><li>兄弟选择器<br> ①相邻兄弟选择器， 是紧挨着他的下一个；语法： 选择器1+选择器2{} <code>div+p { color:red; }</code><br> ②通用兄弟选择器， 选中指定元素后，符合条件的所有兄弟元素；语法：选择器1~ 选择器2{} <code>div~p { color:red;}</code></li><li>属性选择器 ： 选中属性值符合一定要求的元素，如选中title属性值以a开头的元素 <code>div[title^=&quot;a&quot;]{color:red;}</code></li></ol></blockquote><ol start="3"><li>选择器的优先级：行内样式 &gt; ID选择器 &gt; 类选择器 &gt; 元素选择器 &gt; 通配选择器。</li></ol><h3 id="css三大特性" tabindex="-1"><a class="header-anchor" href="#css三大特性" aria-hidden="true">#</a> CSS三大特性</h3><ol><li>层叠性: 如果发生了样式冲突，那就会根据一定的规则（选择器优先级），进行样式的层叠</li><li>继承性: 元素会自动拥有其父元素、或其祖先元素上所设置的某些样式，优先继承离得近的。</li></ol><blockquote><p>a. 会继承的 css 属性： 字体属性、文本属性（除了vertical-align）、文字颜色 等。<br> b. 不会继承的 css 属性： 边框、背景、内边距、外边距、宽高、溢出方式 等。<br> c. 一个规律：能继承的属性，都是不影响布局的，简单说：都是和盒子模型没关系的</p></blockquote><ol start="3"><li>优先级: !important &gt; 行内样式 &gt; ID选择器 &gt; 类选择器 &gt; 元素选择器 &gt; * &gt; 继承的样式。</li></ol><h3 id="css常用属性" tabindex="-1"><a class="header-anchor" href="#css常用属性" aria-hidden="true">#</a> CSS常用属性</h3><ol><li>颜色:支持颜色名称（<code>red</code>）、RGB（<code>rgb(255,0,0)</code>）、十六进制（<code>#RRGGBB</code>）</li></ol><blockquote><ol><li><code>颜色名</code>：直接使用颜色对应的英文单词，编写比较简单</li><li><code>rgb 或 rgba</code>：使用 红、黄、蓝 这三种光的三原色进行组合。 r表示红色；g表示绿色；b表示蓝色；a表示透明度；使用 0~255 之间的数字表示一种颜色</li><li><code>HEX 或 HEXA</code>：通过：红、绿、蓝色 进行组合，只不过要用 6位（分成3组）来表达，格式为：#rrggbb。每一种光的最小值是：00 ，最大值是：ff。所以：<code>红色:color: #ff0000;</code> <code>绿色:color: #00ff00;</code> <code>color: 蓝色:#0000ff;</code></li></ol></blockquote><ol start="2"><li>字体属性：<code>font-size font-family font-style font-weight</code></li><li>文本属性：</li></ol><ul><li><code>text-align</code>：对齐方式（<code>left</code>/<code>center</code>/<code>right</code>）。</li><li><code>text-decoration</code>：下划线（<code>underline</code>）、删除线（<code>line-through</code>）。</li><li><code>line-height</code>：行高控制。</li></ul><ol start="4"><li>列表属性：<code>list-style-type</code>：设置列表符号；<code>list-style-position</code>： 设置列表符号的位置；<code>list-style-image</code>： 自定义列表符号</li><li>表格属性：<code>border-width border-color border-style</code></li><li>背景属性：<code>background-color background-image background-repeat background-position</code></li><li>鼠标属性：<code>cursor</code> 设置鼠标光标的样式；<code>pointer</code>小手；<code>move </code>移动图标；<code>text</code>文字选择器；<code>wait</code>等待；<code>help</code>帮助</li></ol><h3 id="盒子模型" tabindex="-1"><a class="header-anchor" href="#盒子模型" aria-hidden="true">#</a> 盒子模型</h3><p>盒模型都是由四个部分组成的，分别是 margin、border、padding 和 content。盒子的大小 = content + 左右 padding + 左右 border；外边距 margin 不会影响盒子的大小，但会影响盒子的位置。</p><ol><li>margin（外边距）： 盒子与外界的距离。</li><li>border（边框）： 盒子的边框。</li><li>padding（内边距）： 紧贴内容的补白区域。</li><li>content（内容）：元素中的文本或后代元素都是它的内容。</li><li>margin问题：上 margin 、左 margin ：影响自己的位置；下 margin 、右 margin ：影响后面兄弟元素的位置。</li></ol><p>margin 塌陷问题：第一个子元素的上 margin 会作用在父元素上，最后一个子元素的下 margin 会作用在父元素上。</p><blockquote><ul><li>解决：方案一： 给父元素设置不为 0 的 padding; 方案二： 给父元素设置宽度不为 0 的 border; 方案三：给父元素设置overflow:hidden</li></ul></blockquote><p>margin 合并问题：上面兄弟元素的下外边距和下面兄弟元素的上外边距会合并，取一个最大的值，而不是相加。</p><blockquote><ul><li>解决：底部元素变为行内盒子：display: inline-block；底部元素设置浮动：float；底部元素的 position 设为绝对定位</li></ul></blockquote><h3 id="浮动" tabindex="-1"><a class="header-anchor" href="#浮动" aria-hidden="true">#</a> 浮动</h3><ol><li>浮动特点</li></ol><blockquote><ul><li>脱离文档流。</li><li>不管浮动前是什么元素，浮动后：默认宽与高都是被内容撑开且可以设置宽高， 不会独占一行</li><li>不会 margin 合并，也不会 margin 塌陷，能够完美的设置四个方向的 margin 和 padding</li><li>不会像行内块一样被当做文本处理（没有行内块的空白问题）。</li></ul></blockquote><ol start="2"><li>浮动有什么影响</li></ol><blockquote><ul><li>对兄弟元素的影响： 后面的兄弟元素，会占据浮动元素之前的位置，在浮动元素的下面；对前面的兄弟无影响。</li><li>对父元素的影响： 不能撑起父元素的高度，导致父元素高度塌陷；但父元素的宽度依然束缚浮动的元素。</li></ul></blockquote><ol start="3"><li>解决浮动产生的影响</li></ol><blockquote><ul><li>给父元素指定高度。</li><li>给父元素也设置浮动，带来其他影响。</li><li>给父元素设置<code> overflow:hidden</code></li><li>给浮动元素的父元素，设置伪元素，通过伪元素清除浮动。<code>.parent::after { content: &quot;&quot;; display: block; clear:both; }</code></li></ul></blockquote><h3 id="定位" tabindex="-1"><a class="header-anchor" href="#定位" aria-hidden="true">#</a> 定位</h3><ol><li>相对定位：<code>position:relative</code>,参考点是相对自己原来的位置</li></ol><blockquote><ul><li>特点：脱离文档流，会对后面的兄弟元素、父元素有影响。</li></ul></blockquote><ol start="2"><li>绝对定位：<code>position: absolute</code>, 参考点是它的包含块。对于没有脱离文档流的元素：包含块就是父元素；</li></ol><blockquote><ul><li>特点： 不会脱离文档流，定位元素的显示层级比普通元素高。 无论是什么元素（行内、行内块、块级）设置为绝对定位之后，都变成了定位元素（默认宽、高都被内容所撑开，且能自由设置宽高）。</li></ul></blockquote><ol start="3"><li>固定定位：<code>position: fixed</code> , 参考点是视口</li></ol><blockquote><ul><li>特点：不会脱离文档流，定位元素的显示层级比普通元素高。 无论是什么元素（行内、行内块、块级）设置为绝对定位之后，都变成了定位元素（默认宽、高都被内容所撑开，且能自由设置宽高）。</li></ul></blockquote><ol start="4"><li>粘性定位：<code>position:sticky</code>, 参考点是离它最近的一个拥有“滚动机制”的祖先元素</li></ol><blockquote><ul><li>特点： 不会脱离文档流，它是一种专门用于窗口滚动时的新的定位方式。 粘性定位和相对定位的特点基本一致，不同的是：粘性定位可以在元素到达某个位置时将其固定。</li></ul></blockquote><ol start="5"><li>定位层级：定位元素的显示层级比普通元素高。可以通过 css 属性 z-index 调整元素的显示层级，只有定位的元素设置 z-index 才有效。</li></ol><h3 id="元素的显示模式" tabindex="-1"><a class="header-anchor" href="#元素的显示模式" aria-hidden="true">#</a> 元素的显示模式</h3><ol><li>块元素（block）： 在页面中独占一行，默认宽度：撑满父元素， 默认高度：由内容撑开，可以设置宽高。 <code>&lt;h1&gt; ~ &lt;h6&gt; 、 &lt;hr&gt; 、 &lt;p&gt; 、 &lt;pre&gt; 、 &lt;div&gt;、&lt;ul&gt; 、 &lt;ol&gt; 、 &lt;li&gt;</code></li><li>行内元素（inline）： 在页面中不独占一行，默认宽度：由内容撑开， 默认高度：由内容撑开，不能设置宽高 。<code>&lt;br&gt; 、 &lt;em&gt; 、 &lt;strong&gt; 、 &lt;a&gt; 、&lt;label&gt;</code></li><li>行内块元素（inline-block）：在页面中不独占一行，默认宽度：由内容撑开， 默认高度：由内容撑开，可以能设置宽高 。<code>&lt;img&gt;、&lt;input&gt; 、 &lt;textarea&gt; 、 &lt;select&gt; 、 &lt;button&gt;、&lt;td&gt; 、 &lt;th&gt;、&lt;iframe&gt;</code></li></ol><h3 id="参考链接" tabindex="-1"><a class="header-anchor" href="#参考链接" aria-hidden="true">#</a> 参考链接</h3>',45),h={href:"https://www.bilibili.com/video/BV1p84y1P7Z5/?spm_id_from=333.1387.search.video_card.click&vd_source=a3aec2a1dd5f478da3517872d0c61c5c",target:"_blank",rel:"noopener noreferrer"};function u(g,b){const l=i("ExternalLinkIcon");return t(),c("div",null,[s,o("p",null,[o("a",h,[d("html+css教程，前端html5+css3零基础入门，web前端开发"),r(l)])])])}const k=e(n,[["render",u],["__file","CSS2有什么？.html.vue"]]);export{k as default};
